import { useState } from 'react';

export default function App() {
  const [form, setForm] = useState({ nome: '', email: '', mensagem: '' });
  const [enviado, setEnviado] = useState(null);

  const handleChange = (e) => {
    setForm(prev => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setEnviado(form);
  };

  return (
    <form onSubmit={handleSubmit}>
      <input name="nome" value={form.nome} onChange={handleChange} placeholder="Nome" />
      <input name="email" value={form.email} onChange={handleChange} placeholder="Email" />
      <textarea name="mensagem" value={form.mensagem} onChange={handleChange} placeholder="Mensagem" />
      <button type="submit">Enviar</button>
      {enviado && <p>Olá {enviado.nome} ({enviado.email}): {enviado.mensagem}</p>}
    </form>
  );
}
